// Send delivers an outbound message. Dispatches to comment reply or Messenger based on fb_mode metadata.
func (ch *Channel) Send(ctx context.Context, msg bus.OutboundMessage) error {
	mode := msg.Metadata["fb_mode"]

	switch mode {
	case "messenger":
		text := FormatForMessenger(msg.Content)
		parts := splitMessage(text, messengerMaxChars)
		for _, part := range parts {
			if _, err := ch.graphClient.SendMessage(ctx, msg.ChatID, part); err != nil {
				ch.handleAPIError(err)
				return err
			}
		}

	default: // "comment"
		commentID := msg.Metadata["reply_to_comment_id"]
		if commentID == "" {
			return fmt.Errorf("facebook: reply_to_comment_id missing in outbound metadata")
		}
		text := FormatForComment(msg.Content)
		if _, err := ch.graphClient.ReplyToComment(ctx, commentID, text); err != nil {
			ch.handleAPIError(err)
			return err
		}

		// First inbox: send a private DM after comment reply (best-effort).
		if ch.config.Features.FirstInbox {
			senderID := msg.Metadata["sender_id"]
			if senderID != "" {
				ch.sendFirstInbox(ctx, senderID)
			}
		}
	}

	return nil
}

// WebhookHandler returns the shared webhook path and the global router as handler.
// Only the first facebook instance mounts the route; others return ("", nil).
func (ch *Channel) WebhookHandler() (string, http.Handler) {
	return globalRouter.webhookRoute()
}

// handleAPIError maps Graph API errors to channel health states.
func (ch *Channel) handleAPIError(err error) {
	if err == nil {
		return
	}
	switch {
	case IsAuthError(err):
		ch.MarkFailed("token expired", err.Error(), channels.ChannelFailureKindAuth, false)
	case IsPermissionError(err):
		ch.MarkFailed("permission denied", err.Error(), channels.ChannelFailureKindAuth, false)
	case IsRateLimitError(err):
		ch.MarkDegraded("rate limited", err.Error(), channels.ChannelFailureKindNetwork, true)
	default:
		ch.MarkDegraded("api error", err.Error(), channels.ChannelFailureKindUnknown, true)
	}
}

// sendFirstInbox sends a one-time private DM after a comment reply (best-effort).
func (ch *Channel) sendFirstInbox(ctx context.Context, senderID string) {
	if _, alreadySent := ch.firstInboxSent.LoadOrStore(senderID, struct{}{}); alreadySent {
		return
	}
	message := ch.config.FirstInboxMessage
	if message == "" {
		message = "Cảm ơn bạn đã comment! Mình có thể hỗ trợ thêm qua tin nhắn riêng."
	}
	if _, err := ch.graphClient.SendMessage(ctx, senderID, message); err != nil {
		slog.Warn("facebook: first inbox send failed", "sender_id", senderID, "err", err)
		ch.firstInboxSent.Delete(senderID) // allow retry on next comment
	}
}

// runDedupCleaner evicts dedup entries older than dedupTTL every dedupCleanEvery.
func (ch *Channel) runDedupCleaner() {
	ticker := time.NewTicker(dedupCleanEvery)
	defer ticker.Stop()
	for {
		select {
		case <-ch.stopCh:
			return
		case <-ticker.C:
			now := time.Now()
			ch.dedup.Range(func(k, v any) bool {
				if t, ok := v.(time.Time); ok && now.Sub(t) > dedupTTL {
					ch.dedup.Delete(k)
				}
				return true

package facebook

import (
	"fmt"
	"log/slog"
	"strings"
)

// handleCommentEvent processes a feed webhook change where item == "comment".
func (ch *Channel) handleCommentEvent(entry WebhookEntry, change ChangeValue) {
	// Feature gate.
	if !ch.config.Features.CommentReply {
		return
	}

	// Only process new comments (not edits or deletions).
	if change.Verb != "add" {
		return
	}

	// Page routing: ensure this event belongs to our page instance (before dedup write).
	if entry.ID != ch.pageID {
		return
	}

	// Self-reply prevention: skip comments posted by the page itself.
	if change.From.ID == ch.pageID {
		return
	}

	// Dedup: Facebook may deliver the same event more than once.
	if ch.isDup("comment:" + change.CommentID) {
		slog.Debug("facebook: duplicate comment event skipped", "comment_id", change.CommentID)
		return
	}

	// Build message content — optionally enriched with post + thread context.
	// Use stopCtx so inflight Graph API calls are cancelled when the channel stops.
	content := change.Message
	if ch.config.CommentReplyOptions.IncludePostContext && change.PostID != "" {
		content = ch.buildEnrichedContent(change)
	}

	senderID := change.From.ID
	// Session key groups all comments by the same user on the same post.
	chatID := fmt.Sprintf("%s:%s", change.PostID, senderID)

	metadata := map[string]string{
		"comment_id":          change.CommentID,
		"post_id":             change.PostID,
		"parent_id":           change.ParentID,
		"sender_name":         change.From.Name,
		"sender_id":           senderID,
		"fb_mode":             "comment",
		"reply_to_comment_id": change.CommentID,
	}

	ch.HandleMessage(senderID, chatID, content, nil, metadata, "direct")
}

// buildEnrichedContent fetches post content and comment thread, assembles a rich
// context string for the agent. Uses stopCtx so it is cancelled on channel Stop().
func (ch *Channel) buildEnrichedContent(change ChangeValue) string {
	ctx := ch.stopCtx

	var sb strings.Builder

	// Post content.
	post, err := ch.postFetcher.GetPost(ctx, change.PostID)
	if err == nil && post != nil && post.Message != "" {
		sb.WriteString("[Bài đăng] ")
		sb.WriteString(post.Message)
		sb.WriteString("\n\n")
	}

	// Comment thread (when this is a nested reply).
	if change.ParentID != "" {
		depth := ch.config.CommentReplyOptions.MaxThreadDepth
		if depth <= 0 {
			depth = 10
		}
		thread, err := ch.postFetcher.GetCommentThread(ctx, change.ParentID, depth)
		if err == nil && len(thread) > 0 {
			sb.WriteString("[Thread]\n")
			for _, c := range thread {
				sb.WriteString(fmt.Sprintf("- %s: %s\n", c.From.Name, c.Message))
			}
			sb.WriteString("\n")
		}
	}

	// Current comment.
	sb.WriteString("[Comment mới] ")
	sb.WriteString(change.From.Name)
	sb.WriteString(": ")
	sb.WriteString(change.Message)

	return sb.String()
}

