		"event_type", event.EventType,
		"page_id", pageID,
		"conv_id", data.Conversation.ID,
		"conv_type", convType,
		"sender_id", data.Conversation.From.ID,
		"sender_name", data.Conversation.From.Name,
		"msg_id", data.Message.ID)

