package pancake

import (
	"fmt"
	"log/slog"
	"strings"

	"github.com/nextlevelbuilder/goclaw/internal/channels"
)

// handleCommentEvent routes Pancake COMMENT webhooks through the agent pipeline.
func (ch *Channel) handleCommentEvent(data MessagingData) {
	if !ch.config.Features.CommentReply {
		slog.Debug("pancake: comment reply feature disabled", "page_id", ch.pageID, "msg_id", data.Message.ID)
		return
	}

	// Dedup before enrichment so echoed/comment duplicates cannot bypass by prefix mismatch.
	var dedupKey string
	if data.Message.ID != "" {
		dedupKey = fmt.Sprintf("comment:%s", data.Message.ID)
		if ch.isDup(dedupKey) {
			slog.Info("pancake: duplicate comment skipped", "comment_id", data.Message.ID)
			return
		}
	}

	// Prevent reply loops from page/staff authored comments.
	if data.Message.SenderID == ch.pageID {
		slog.Info("pancake: skipping own page comment", "page_id", ch.pageID, "sender_id", data.Message.SenderID)
		return
	}
	if isAssignedStaff(data.AssigneeIDs, data.Message.SenderID) {
		slog.Info("pancake: skipping assigned staff comment", "page_id", ch.pageID, "sender_id", data.Message.SenderID)
		return
	}
	if data.Message.SenderID == "" {
		slog.Warn("pancake: comment missing sender_id, skipping", "msg_id", data.Message.ID)
		return
	}

	// Echo dedup must run before buildCommentContent prepends any post context.
	if ch.isRecentOutboundEcho(data.Message.ID, data.Message.Content) || ch.isRecentOutboundEcho(data.ConversationID, data.Message.Content) {
		slog.Info("pancake: skipping recent outbound comment echo", "page_id", ch.pageID, "comment_id", data.Message.ID)
		return
	}

	if !ch.commentMatchesFilter(data.Message.Content) {
		slog.Debug("pancake: comment skipped by keyword filter", "page_id", ch.pageID, "comment_id", data.Message.ID)
		return
	}

	content := ch.buildCommentContent(data)
	postID := ch.postIDFromConversation(data.ConversationID)
	chatID := data.ConversationID
	if postID != "" && data.Message.SenderID != "" {
		chatID = fmt.Sprintf("%s:%s", postID, data.Message.SenderID)
	}

	metadata := map[string]string{
		"pancake_mode":        "comment",
		"conversation_type":   data.Type,
		"platform":            data.Platform,
		"conversation_id":     data.ConversationID,
		"comment_id":          data.Message.ID,
		"reply_to_comment_id": data.Message.ID,
		"sender_id":           data.Message.SenderID,
		"sender_name":         data.Message.SenderName,
		"message_id":          dedupKey,
		"display_name":        channels.SanitizeDisplayName(data.Message.SenderName),
		"page_name":           ch.pageName,
	}
	if postID != "" {
		metadata["post_id"] = postID
	}

	ch.HandleMessage(data.Message.SenderID, chatID, content, nil, metadata, "direct")
}

func (ch *Channel) commentMatchesFilter(content string) bool {
	opts := ch.config.CommentReplyOptions
	if !strings.EqualFold(opts.Filter, "keyword") {
		return true
	}
	content = strings.ToLower(stripHTML(content))
	for _, kw := range opts.Keywords {
		kw = strings.ToLower(strings.TrimSpace(kw))
		if kw != "" && strings.Contains(content, kw) {
			return true
		}
	}
	return false
}

func (ch *Channel) buildCommentContent(data MessagingData) string {
	body := buildMessageContent(data)
	if !ch.config.CommentReplyOptions.IncludePostContext {
		return body
	}
	postText := ch.postTextForComment(data)
	if postText == "" {
		return body
	}
	if body == "" {
		return "[Post] " + postText
	}
	return "[Post] " + postText + "\n\n[Comment] " + body
}

func (ch *Channel) postTextForComment(data MessagingData) string {
	if data.Post != nil {
		return pancakePostText(data.Post)
	}
	if ch.postFetcher == nil {
		return ""
	}
	postID := ch.postIDFromConversation(data.ConversationID)
	if postID == "" {
		return ""
	}
	post, err := ch.postFetcher.GetPost(ch.stopCtx, postID)
	if err != nil || post == nil {
		if err != nil {
			slog.Debug("pancake: post context fetch failed", "page_id", ch.pageID, "post_id", postID, "err", err)
		}
		return ""
	}
	return pancakePostText(post)
}

func (ch *Channel) postIDFromConversation(conversationID string) string {
	if conversationID == "" {
		return ""
	}
	if idx := strings.Index(conversationID, "_"); idx > 0 {
		return conversationID[:idx]
	}
	if idx := strings.Index(conversationID, ":"); idx > 0 {
		return conversationID[:idx]
	}
	return conversationID
}

func pancakePostText(post *PancakePost) string {
	if post == nil {
		return ""
	}
	for _, candidate := range []string{post.Message, post.Content, post.Caption, post.Story} {
		if s := strings.TrimSpace(stripHTML(candidate)); s != "" {
			return s
		}
	}
	return ""
}

