	stopCtx, stopFn := context.WithCancel(context.Background())

	apiClient := NewAPIClient(creds.APIKey, creds.PageAccessToken, cfg.PageID)
	ch := &Channel{
		BaseChannel:   base,
		config:        cfg,
		apiClient:     apiClient,
		pageID:        cfg.PageID,
