	if ch.platform == "" || ch.pageName == "" {
		if page, err := ch.apiClient.GetPage(ctx); err != nil {
			slog.Warn("pancake: could not resolve platform from page metadata", "page_id", ch.pageID, "err", err)
		} else {
			if page.Platform != "" {
