func (ch *Channel) maxMessageLength() int {
	switch ch.platform {
	case "tiktok":
		return 500
	case "instagram":
		return 1000
	case "facebook", "zalo":
		return 2000
	case "whatsapp":
		return 4096
	case "line":
		return 5000
	default:
		return 2000
	}
}

