package pancake

import (
	"context"
	"sync"
	"time"

	"golang.org/x/sync/singleflight"
)

const defaultPancakePostCacheTTL = 15 * time.Minute

type pancakePostsCacheEntry struct {
	posts     []PancakePost
	expiresAt time.Time
}

// PostFetcher caches Pancake's list-all-posts API. Pancake does not expose the
// same per-post lookup contract as Facebook Graph, so the singleflight key is
// deliberately global ("posts") to prevent stampedes on busy pages.
type PostFetcher struct {
	apiClient *APIClient
	cacheTTL  time.Duration
	cache     sync.Map
	sfGroup   singleflight.Group
}

func NewPostFetcher(client *APIClient, cacheTTLStr string) *PostFetcher {
	ttl := defaultPancakePostCacheTTL
	if cacheTTLStr != "" {
		if d, err := time.ParseDuration(cacheTTLStr); err == nil && d > 0 {
			ttl = d
		}
	}
	return &PostFetcher{apiClient: client, cacheTTL: ttl}
}

func (pf *PostFetcher) GetPost(ctx context.Context, postID string) (*PancakePost, error) {
	if pf == nil || pf.apiClient == nil || postID == "" {
		return nil, nil
	}
	posts, err := pf.getPosts(ctx)
	if err != nil {
		return nil, err
	}
	for i := range posts {
		if posts[i].ID == postID || posts[i].PostID == postID {
			return &posts[i], nil
		}
	}
	return nil, nil
}

func (pf *PostFetcher) getPosts(ctx context.Context) ([]PancakePost, error) {
	const cacheKey = "posts"
	if v, ok := pf.cache.Load(cacheKey); ok {
		entry := v.(*pancakePostsCacheEntry)
		if time.Now().Before(entry.expiresAt) {
			return entry.posts, nil
		}
		pf.cache.Delete(cacheKey)
	}

	val, err, _ := pf.sfGroup.Do(cacheKey, func() (any, error) {
		if v, ok := pf.cache.Load(cacheKey); ok {
			entry := v.(*pancakePostsCacheEntry)
			if time.Now().Before(entry.expiresAt) {
				return entry.posts, nil
			}
		}
		posts, err := pf.apiClient.ListPosts(ctx)
		if err != nil {
			return nil, err
		}
		pf.cache.Store(cacheKey, &pancakePostsCacheEntry{posts: posts, expiresAt: time.Now().Add(pf.cacheTTL)})
		return posts, nil
	})
	if err != nil {
		return nil, err
	}
	if val == nil {
		return nil, nil
	}
	return val.([]PancakePost), nil
}

