	target.config.Features.CommentReply = true
	router := &webhookRouter{
		instances: map[string]*Channel{
			"page-123": target,
		},
	}

	body := `{
		"page_id": "page-123",
		"event_type": "messaging",
		"data": {
			"conversation": {
				"id": "post-123_user-1",
				"type": "COMMENT",
				"from": {
					"id": "user-1",
					"name": "Customer"
				}
			},
			"message": {
				"id": "comment-1",
				"message": "hi"
			}
		}
	}`

	req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("status = %d, want %d", w.Code, http.StatusOK)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	msg, ok := msgBus.ConsumeInbound(ctx)
	if !ok {
		t.Fatal("expected COMMENT conversation webhook to be published")
