func TestSendCommentUsesReplyCommentAndPrivateReplyOnce(t *testing.T) {
	api := NewAPIClient("user-token", "page-token", "page-123")
	var actions []string
	sendServer := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			t.Fatalf("read request body: %v", err)
		}
		if strings.Contains(r.URL.Path, "/conversations/comment-1/messages") || strings.Contains(r.URL.Path, "/conversations/user-1/messages") {
			if strings.Contains(string(body), `"action":"reply_comment"`) {
				actions = append(actions, "reply_comment")
			}
			if strings.Contains(string(body), `"action":"private_reply"`) {
				actions = append(actions, "private_reply")
			}
		}
		w.Header().Set("Content-Type", "application/json")
		_, _ = io.WriteString(w, `{"success":true}`)
	}))
	defer sendServer.Close()

	api.pageV1BaseURL = sendServer.URL
	api.httpClient = sendServer.Client()

	ch := &Channel{apiClient: api, pageID: "page-123"}
	ch.config.Features.FirstInbox = true
	ch.config.FirstInboxMessage = "hello inbox"

	for i := 0; i < 2; i++ {
		if err := ch.Send(context.Background(), bus.OutboundMessage{
			ChatID:  "post-123:user-1",
			Content: "comment reply",
			Metadata: map[string]string{
				"pancake_mode":        "comment",
				"reply_to_comment_id": "comment-1",
				"sender_id":           "user-1",
			},
		}); err != nil {
			t.Fatalf("Send returned error: %v", err)
		}
	}

	if got, want := strings.Join(actions, ","), "reply_comment,private_reply,reply_comment"; got != want {
		t.Fatalf("actions = %q, want %q", got, want)
	}
}

