package pancake

import (
	"context"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/nextlevelbuilder/goclaw/internal/bus"
	"github.com/nextlevelbuilder/goclaw/internal/channels"
)

func TestMessageHandlerSkipsRecentOutboundEchoWithHTMLFormatting(t *testing.T) {
	msgBus := bus.New()
	ch := &Channel{
		BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
		pageID:      "page-123",
	}
	ch.rememberOutboundEcho("conv-1", "Line 1\nLine 2")

	ch.handleMessagingEvent(MessagingData{
		PageID:         "page-123",
		ConversationID: "conv-1",
		Type:           "INBOX",
		Platform:       "facebook",
		Message: MessagingMessage{
			ID:       "msg-echo-html-1",
			SenderID: "user-1",
			Content:  "<div>Line 1<br key='n_0' />Line 2</div>",
		},
	})

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	if _, ok := msgBus.ConsumeInbound(ctx); ok {
		t.Fatal("expected HTML-formatted echo to be dropped")
	}
}

func TestWebhookRouterRoutesCommentEventsWhenEnabled(t *testing.T) {
	msgBus := bus.New()
	target := &Channel{
		BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
		pageID:      "page-123",
		platform:    "facebook",
	}
	target.config.Features.CommentReply = true
	router := &webhookRouter{
		instances: map[string]*Channel{
			"page-123": target,
		},
	}

	body := `{
		"page_id": "page-123",
		"event_type": "messaging",
		"data": {
			"conversation": {
				"id": "post-123_user-1",
				"type": "COMMENT",
				"from": {
					"id": "user-1",
					"name": "Customer"
				}
			},
			"message": {
				"id": "comment-1",
				"message": "hi"
			}
		}
	}`

	req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("status = %d, want %d", w.Code, http.StatusOK)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	msg, ok := msgBus.ConsumeInbound(ctx)
	if !ok {
		t.Fatal("expected COMMENT conversation webhook to be published")
	}
	if got, want := msg.Metadata["pancake_mode"], "comment"; got != want {
		t.Fatalf("pancake_mode = %q, want %q", got, want)
	}
	if got, want := msg.Metadata["reply_to_comment_id"], "comment-1"; got != want {
		t.Fatalf("reply_to_comment_id = %q, want %q", got, want)
	}
}

func TestWebhookRouterPrefersMessageSenderOverConversationSender(t *testing.T) {
	msgBus := bus.New()
	target := &Channel{
		BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
		pageID:      "page-123",
		platform:    "facebook",
	}
	router := &webhookRouter{
		instances: map[string]*Channel{
			"page-123": target,
		},
	}

	body := `{
		"page_id": "page-123",
		"event_type": "messaging",
		"data": {
			"conversation": {
				"id": "conv-1",
				"type": "INBOX",
				"from": {
					"id": "user-initiator",
					"name": "Conversation Starter"
				}
			},
			"message": {
				"id": "msg-actual-sender-1",
				"message": "xin chao",
				"from": {
					"id": "user-actual",
					"name": "Actual Sender",
					"page_customer_id": "pc-123"
				}
			}
		}
	}`

	req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("status = %d, want %d", w.Code, http.StatusOK)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	msg, ok := msgBus.ConsumeInbound(ctx)
	if !ok {
		t.Fatal("expected inbound message to be published")
	}
	if got, want := msg.SenderID, "user-actual"; got != want {
		t.Fatalf("sender_id = %q, want %q", got, want)
	}
	if got, want := msg.Metadata["display_name"], "Actual Sender"; got != want {
		t.Fatalf("metadata.display_name = %q, want %q", got, want)
	}
}

