func TestWebhookRouterSkipsCommentEventsWhenFeatureDisabled(t *testing.T) {
	msgBus := bus.New()
	target := &Channel{
		BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
		pageID:      "page-123",
		platform:    "facebook",
	}
	router := &webhookRouter{
		instances: map[string]*Channel{
			"page-123": target,
		},
	}

	body := `{
		"page_id": "page-123",
		"event_type": "messaging",
		"data": {
			"conversation": {
				"id": "page-123_user-1",
				"type": "COMMENT",
				"from": {
					"id": "user-1",
					"name": "Customer"
				}
			},
			"message": {
				"id": "msg-comment-1",
				"message": "hi"
			}
		}
	}`

	req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("status = %d, want %d", w.Code, http.StatusOK)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	if _, ok := msgBus.ConsumeInbound(ctx); ok {
		t.Fatal("expected COMMENT conversation webhook to be ignored when feature is disabled")
	}
}

func TestWebhookRouterPrefersMessageSenderOverConversationSender(t *testing.T) {
